import { pick } from '../../utils/zcutils';
import { svg_clips } from '../../effects/svg-clips';
import { $Browser } from '../../core/browser-detect';
import { effects } from '../../effects/zceffects';

/**
 *
 * @type {{GET_DOMAIN(*=, *=, *, *=, *=): *[], CALCULATE_DOMAIN(*, *=, *=, *=, *=): *[], GET_DOMAIN_INFO(*=, *=, *=, *=): {}}}
 */
export var CHART_BRUSH_HELPERS = {
    CLIP_TRACK(brushInstance, selection, chart, name, options = {}) {
        let clipSrc = getClip(brushInstance, selection, chart, name, options);
        brushInstance._track.attr('clip-path', clipSrc);

        return clipSrc;
    },
    GET_CLIP: getClip
};

function getClip(brushInstance, selection, chart, name, options = {}) {
    var desc = pick(options.desc, RectClip(brushInstance, selection));

    var properties = { d: desc, name: 'brush', id: chart.id },
        // #ZC2212 $name
        scroll_clip_id = `brush_tracker_clip_${name}_${chart.id}`;

    if ($Browser.PHANTOMJS) {
        scroll_clip_id = effects.get(effects.svg_clips, 'polygon', properties, { chartObj: chart });
    } else {
        svg_clips.polygon(properties, scroll_clip_id, null, null, null, chart);
    }

    return `url(${chart.defsLocation}#${scroll_clip_id})`;
}

function RectClip(brushInstance, selection) {
    let start = [0, 0],
        desc,
        dimension = brushInstance.d3_brush.extent()()[1];

    selection = selection || brushInstance.getSelection();

    if (brushInstance.options.type === 'x') {
        desc =
            `M${start[0]} ${start[1]}L${selection[0]} ${start[1]}L${selection[0]} ${dimension[1]}L${start[0]} ${dimension[1]}Z` +
            `M${selection[1]} ${start[1]}L${dimension[0]} ${start[1]}L${dimension[0]} ${dimension[1]}L${selection[1]} ${dimension[1]}Z`;
    } else {
        desc =
            `M${start[0]} ${start[1]}L${dimension[0]} ${start[1]}L${dimension[0]} ${selection[0]}L${start[0]} ${selection[0]}Z` +
            `M${start[0]} ${selection[1]}L${dimension[0]} ${selection[1]}L${dimension[0]} ${dimension[1]}L${start[0]} ${dimension[1]}Z`;
    }

    return desc;
}
